from math import prod
from Crypto.Util.number import long_to_bytes
import gmpy2

def crt_recover(ci_list, ni_list, e):
    # N = n1 * n2 * ... * n_e
    N = prod(ni_list)
    
    C = 0
    for ci, ni in zip(ci_list, ni_list):
        Mi = N // ni
        inv = pow(Mi, -1, ni)
        C += ci * inv * Mi
    C %= N
    
    m_root, exact = gmpy2.iroot(C, e)
    return long_to_bytes(int(m_root))

